import json
from openai import OpenAI

client = OpenAI()

SUPPORT_SYSTEM_PROMPT = """You are a helpful customer support agent for Acme Inc.
Only answer questions about Acme products and services.
Always cite the KB article you're drawing from (provide the article URL).
Be empathetic: acknowledge frustration before providing solutions.
Never repeat credit card numbers, SSNs, or passwords back in your responses.
If you cannot resolve the issue after 2 attempts, call escalate_to_human."""

SUPPORT_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "kb_search",
            "description": "Search the knowledge base for articles relevant to the user's question.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {"type": "string"},
                    "top_k": {"type": "integer", "default": 5},
                },
                "required": ["query"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "get_account",
            "description": "Retrieve account details for an authenticated user.",
            "parameters": {
                "type": "object",
                "properties": {
                    "user_id": {"type": "string"},
                },
                "required": ["user_id"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "issue_refund",
            "description": "Issue a refund for an order. Only call for amounts <= $150; escalate otherwise.",
            "parameters": {
                "type": "object",
                "properties": {
                    "order_id": {"type": "string"},
                    "amount": {"type": "number"},
                    "reason": {"type": "string"},
                },
                "required": ["order_id", "amount", "reason"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "escalate_to_human",
            "description": "Hand off to a human agent. Call when you cannot resolve the issue, the user is frustrated, or a policy exception is needed.",
            "parameters": {
                "type": "object",
                "properties": {
                    "reason": {"type": "string"},
                    "priority": {"type": "string", "enum": ["low", "normal", "high", "urgent"]},
                    "summary": {"type": "string", "description": "1-2 sentence summary for the human agent."},
                },
                "required": ["reason", "priority", "summary"],
            },
        },
    },
]


def support_agent_turn(
    conversation_id: str,
    user_message: str,
    user_id: str,
    store: ConversationStore,
    tool_executor,  # callable(name, args) -> result
) -> str:
    """Process one user turn; return the agent's reply."""
    history = store.load(conversation_id)
    if not history:
        history = [{"role": "system", "content": SUPPORT_SYSTEM_PROMPT}]

    history = store.append(conversation_id, {"role": "user", "content": user_message})

    for _ in range(10):  # step cap
        response = client.chat.completions.create(
            model="claude-opus-4-8",
            messages=history,
            tools=SUPPORT_TOOLS,
            tool_choice="auto",
        )
        msg = response.choices[0].message
        history = store.append(conversation_id, msg.model_dump())

        if not msg.tool_calls:
            return msg.content or ""

        for tc in msg.tool_calls:
            args = json.loads(tc.function.arguments)
            result = tool_executor(tc.function.name, args)
            history = store.append(conversation_id, {
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result),
            })

    return "I'm connecting you with a member of our team who can help further."

import re

FRUSTRATION_SIGNALS = [
    r"\b(unacceptable|ridiculous|terrible|awful|worst|disgusting)\b",
    r"\b(talk to (a|the) (human|person|agent|representative))\b",
    r"\b(cancel (my )?(account|subscription|order))\b",
    r"\b(this is (the )?third time|again|still not|never resolved)\b",
]


def detect_frustration(user_message: str) -> bool:
    """Heuristic pre-check; escalate immediately if signals present."""
    text = user_message.lower()
    return any(re.search(pat, text) for pat in FRUSTRATION_SIGNALS)


def should_escalate_proactively(
    user_message: str,
    failed_attempts: int,
    escalation_threshold: int = 2,
) -> tuple[bool, str]:
    """Returns (should_escalate, reason)."""
    if detect_frustration(user_message):
        return True, "user expressed frustration"
    if failed_attempts >= escalation_threshold:
        return True, f"unresolved after {failed_attempts} attempts"
    return False, ""
